//! On-disk state for monster-guard, under `$MONSTER_GUARD_HOME` (default
//! `~/.moonshine.d`):
//!   root.key            root authority secret (hex, 0600)
//!   grants/<name>.ucan  per-command delegation token ("command grant")
//!   revocations.json    RevocationSet (token hashes / issuer DIDs / jti)

use std::os::unix::fs::PermissionsExt;
use std::path::PathBuf;

use a0n_auth::{Keypair, RevocationSet};

pub fn home() -> PathBuf {
    if let Ok(h) = std::env::var("MONSTER_GUARD_HOME") {
        return PathBuf::from(h);
    }
    let base = std::env::var("HOME").unwrap_or_else(|_| ".".to_string());
    PathBuf::from(base).join(".moonshine.d")
}

/// Plugin names index files; reject anything that could escape the grants dir.
pub fn valid_name(name: &str) -> bool {
    !name.is_empty()
        && name
            .chars()
            .all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_' || c == '.')
        && name != "."
        && name != ".."
        && !name.contains('/')
}

/// Load the root authority, generating + persisting it on first use.
pub fn ensure_root() -> Result<Keypair, String> {
    let dir = home();
    std::fs::create_dir_all(&dir).map_err(|e| format!("create {}: {e}", dir.display()))?;
    let key_path = dir.join("root.key");
    if key_path.exists() {
        let hex = std::fs::read_to_string(&key_path).map_err(|e| e.to_string())?;
        Keypair::from_secret_hex(hex.trim()).map_err(|e| e.to_string())
    } else {
        let kp = Keypair::generate();
        std::fs::write(&key_path, kp.secret_hex()).map_err(|e| e.to_string())?;
        let _ = std::fs::set_permissions(&key_path, std::fs::Permissions::from_mode(0o600));
        Ok(kp)
    }
}

pub fn grant_path(name: &str) -> PathBuf {
    home().join("grants").join(format!("{name}.ucan"))
}

pub fn save_grant(name: &str, token: &str) -> Result<(), String> {
    let path = grant_path(name);
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    std::fs::write(&path, token).map_err(|e| e.to_string())
}

pub fn load_grant(name: &str) -> Option<String> {
    std::fs::read_to_string(grant_path(name))
        .ok()
        .map(|s| s.trim().to_string())
}

pub fn revocations_path() -> PathBuf {
    home().join("revocations.json")
}

pub fn load_revocations() -> RevocationSet {
    match std::fs::read_to_string(revocations_path()) {
        Ok(s) => serde_json::from_str(&s).unwrap_or_default(),
        Err(_) => RevocationSet::default(),
    }
}

pub fn save_revocations(rev: &RevocationSet) -> Result<(), String> {
    let dir = home();
    std::fs::create_dir_all(&dir).map_err(|e| e.to_string())?;
    let json = serde_json::to_string_pretty(rev).map_err(|e| e.to_string())?;
    std::fs::write(revocations_path(), json).map_err(|e| e.to_string())
}
